mapper.select:
SELECT p.id, p.user_id, p.name, p.description, p.category, p.age_range, p.season, p.material,
       p.certification, p.price, p.original_price, p.sales, p.stock, p.badge, p.image_url, p.status,
       u.enterprise_name
FROM products p
LEFT JOIN users u ON p.user_id = u.id
WHERE p.status = 1

    AND (p.name LIKE CONCAT('%', #{request.keyword}, '%')
       OR p.description LIKE CONCAT('%', #{request.keyword}, '%')
       OR p.category LIKE CONCAT('%', #{request.keyword}, '%'))


    AND p.category = #{request.category}


    AND p.age_range = #{request.ageRange}


    AND p.season LIKE CONCAT('%', #{request.season}, '%')


    AND p.material = #{request.material}


    AND p.certification = #{request.certification}


    AND p.badge = #{request.badge}


    AND p.price >= #{request.minPrice}


    AND p.price <= #{request.maxPrice}

ORDER BY


            p.price ${request.sortOrder == 'asc' ? 'ASC' : 'DESC'}


            p.created_at ${request.sortOrder == 'asc' ? 'ASC' : 'DESC'}


            p.sales DESC


            p.sales DESC, p.created_at DESC



    LIMIT #{request.offset}, #{request.pageSize}

SELECT COUNT(*)
FROM products p
WHERE p.status = 1

    AND (p.name LIKE CONCAT('%', #{request.keyword}, '%')
       OR p.description LIKE CONCAT('%', #{request.keyword}, '%')
       OR p.category LIKE CONCAT('%', #{request.keyword}, '%'))


    AND p.category = #{request.category}


    AND p.age_range = #{request.ageRange}


    AND p.season LIKE CONCAT('%', #{request.season}, '%')


    AND p.material = #{request.material}


    AND p.certification = #{request.certification}


    AND p.badge = #{request.badge}


    AND p.price >= #{request.minPrice}


    AND p.price <= #{request.maxPrice}
